<span class="line"><span style="color:#CDD6F4;">  tool</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> string</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">            // Which tool would be used (Edit, Bash, etc.)</span></span>
